import type { FC } from 'react';
import { cn } from '@/lib/utils';
import { type IconProps, type SvgProps, sizeMap } from '../types';

export type DiffProps = IconProps;

const DiffLight: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <path
      fillRule="evenodd"
      clipRule="evenodd"
      d="M5.854 8.146a.5.5 0 1 0-.708.708L7.293 11H.5a.5.5 0 0 0 0 1h6.793l-2.147 2.146a.5.5 0 0 0 .708.708l3-3 .353-.354-.353-.354zM10.146 1.146a.5.5 0 0 1 .708.708L8.707 4H15.5a.5.5 0 0 1 0 1H8.707l2.147 2.146a.5.5 0 0 1-.708.708l-3-3-.353-.354.353-.354z"
      fill="#6C707E"
    />
  </svg>
);

const DiffDark: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <path
      fillRule="evenodd"
      clipRule="evenodd"
      d="M5.854 8.146a.5.5 0 1 0-.708.708L7.293 11H.5a.5.5 0 0 0 0 1h6.793l-2.147 2.146a.5.5 0 0 0 .708.708l3-3 .353-.354-.353-.354zM10.146 1.146a.5.5 0 0 1 .708.708L8.707 4H15.5a.5.5 0 0 1 0 1H8.707l2.147 2.146a.5.5 0 0 1-.708.708l-3-3-.353-.354.353-.354z"
      fill="#CED0D6"
    />
  </svg>
);

export const Diff: FC<DiffProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent = mode === 'light' ? DiffLight : DiffDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
